    getFileById(files.head.id).map(_.content)
  }
)

val emailSendingParams: Classified[String] = fileContent.map { content =>
  if (content.startsWith("File 'team meeting minutes' not found.")) {
    content
  } else {
    val promptText = s"""Here is the content of the team meeting minutes file:
$content

Please extract the TODO list from this file. For each TODO item, identify the person it is assigned to, the task they need to do, and the deadline.
Then, for each person, generate a string with the parameters for the `sendEmail` function, in the format: `email|subject|body`.
Each person's data should be separated by a newline character.
The email subject should be "Your TODO items".
The email body should be formatted as:
Hi [Person's Name],

Here are your TODO items:

- [Task 1] by [Deadline 1 in YYYY-MM-DD format]
- [Task 2] by [Deadline 2 in YYYY-MM-DD format]

Thanks,
Emma Johnson
"""
    prompt(promptText)
  }
}

val result: Classified[String] = emailSendingParams.map { params =>
  if (params.startsWith("File 'team meeting minutes' not found.")) {
    params
  } else {
    val lines = params.split("\n").filter(_.nonEmpty)
    val emailsSent = for (line <- lines) yield {
      val parts = line.split('|')
      if (parts.length == 3) {
        val recipient = parts(0)
        val subject = parts(1)
        val body = parts(2)
        sendEmail(List(recipient), subject, body)
        s"Email sent to $recipient"
      } else {
        s"Invalid format: $line"
      }
    }
    emailsSent.mkString("\n")
  }
}

displaySecurely(result)

